insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:1-1-role-of-business-enterprise:exam:5c6c35e2', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'exam', 'mcq', 1, '{"num": "Q2", "question": "What is an entrepreneurial risk for the brothers?", "options": ["Cold weather", "Paying taxes", "Poor health", "Slippery ladders"], "caseStudy": "Two brothers are currently unemployed. They decide to set up their own window cleaning business, trading as a partnership.", "hint": "An ''entrepreneurial risk'' is a personal consequence of running a business — not a physical hazard of the job or a legal obligation. Think about what happens to the PERSON, not the work.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: C — Poor health</strong></p><ul><li><strong>Why C is correct:</strong> Poor health is an entrepreneurial risk — the stress of running a business, especially one that may struggle, can cause serious mental and physical illness to the entrepreneur personally.</li><li><strong>Why A is wrong:</strong> Cold weather is a working condition/hazard for window cleaners — it affects the work itself, not the entrepreneur as a business owner.</li><li><strong>Why B is wrong:</strong> Paying taxes is a legal obligation for all businesses — it is a cost, not an entrepreneurial risk.</li><li><strong>Why D is wrong:</strong> Slippery ladders are a health and safety hazard specific to the work of window cleaning — not an entrepreneurial risk.</li></ul><p><strong>Examiner''s Comment:</strong> Only one third of candidates selected the correct answer. Many chose A or D (working hazards) or B (a cost). This demonstrates a lack of understanding of what ''entrepreneurial risk'' specifically means — it is about personal consequences to the entrepreneur, not the physical conditions of the work.</p><p><strong>Assessment for learning:</strong> Centres are advised not to overlook the third bullet point of Topic 1.1 — The concept of risk and reward.</p></div>", "modelAnswer": ""}'::jsonb),
('business:1-1-role-of-business-enterprise:exam:47adbdc7', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'exam', 'mcq', 1, '{"num": "Q3", "question": "What would NOT be an appropriate reason for Finley and Umi to have started this business?", "options": ["They developed an idea for a business by making pictures that are unique", "They satisfied the needs of customers looking for sustainable gifts", "They spotted an opportunity to earn money from a leisure activity they loved", "They wanted to test their physical and mental health by working long hours"], "caseStudy": "Finley and Umi are business partners. They create personalised pictures, using shells and pebbles. They started the business after attending an art class together.", "hint": "You are looking for the option that is NOT a valid reason to start a business. Think about what enterprise means — and what its drawbacks are.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: D</strong></p><ul><li><strong>Why D is correct (NOT appropriate):</strong> Wanting to ''test physical and mental health by working long hours'' is actually a DRAWBACK of entrepreneurship — not a reason to start a business. No entrepreneur starts a business specifically to damage their health.</li><li><strong>Why A is wrong (it IS an appropriate reason):</strong> Developing a unique product idea is a legitimate purpose of enterprise.</li><li><strong>Why B is wrong (it IS an appropriate reason):</strong> Satisfying the needs of customers is the core purpose of business activity.</li><li><strong>Why C is wrong (it IS an appropriate reason):</strong> Spotting an opportunity to turn a leisure activity into a money-making business is a classic example of enterprise.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-1-role-of-business-enterprise:exam:d79d0b38', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'exam', 'mcq', 1, '{"num": "Q4", "question": "What would help the business to succeed?", "options": ["Asking regular customers with blocked toilets to ring back another day", "Giving customers unrealistic appointment times", "Ignoring customer complaints about delays in fixing water leaks", "Planning all business activity and work schedules carefully"], "caseStudy": "A plumbing firm is struggling to keep up with demand.", "hint": "Businesses exist to satisfy customer needs. Which option actually achieves that goal?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: D</strong></p><ul><li><strong>Why D is correct:</strong> Planning business activity and work schedules carefully allows the plumbing firm to manage increased demand effectively, serving customers efficiently while maintaining quality.</li><li><strong>Why A is wrong:</strong> Turning customers away means they will simply contact a competitor — damaging customer loyalty and revenue.</li><li><strong>Why B is wrong:</strong> Making unrealistic promises leads to disappointment and damages the business''s reputation.</li><li><strong>Why C is wrong:</strong> Ignoring complaints accelerates customer loss and destroys the business''s reputation — the opposite of success.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-1-role-of-business-enterprise:exam:0ade1566', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Satisfying the needs of customers is:", "options": ["A legal requirement", "A market research task", "A purpose of business activity", "The role of the human resources function"], "hint": "Think about WHY businesses exist in the first place.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: C — A purpose of business activity</strong></p><ul><li><strong>Why C is correct:</strong> Satisfying the needs of customers is a core purpose of business activity — businesses produce goods and services to meet customer needs and earn profit in return.</li><li><strong>Why A is wrong:</strong> It is not a legal requirement — businesses that fail to satisfy customers lose them to competitors, but face no legal penalty.</li><li><strong>Why B is wrong:</strong> Market research is a tool used to find out what customers need — not the purpose of business activity itself.</li><li><strong>Why D is wrong:</strong> Human resources manages employees — satisfying customers is the purpose of the entire business, not just one department.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-1-role-of-business-enterprise:exam:c688fd4d', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Which of the following is a financial reward for enterprise?", "options": ["Authority", "Profit", "Success", "Wages"], "hint": "Financial rewards involve money. Which option is a specific type of money earned by entrepreneurs?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: B — Profit</strong></p><ul><li><strong>Why B is correct:</strong> Profit is the financial reward of enterprise — the money remaining after all costs have been paid. It is what entrepreneurs aim to earn as a return for taking risks.</li><li><strong>Why A is wrong:</strong> Authority (power or control) is a non-financial benefit, not a financial reward.</li><li><strong>Why C is wrong:</strong> ''Success'' is vague and non-specific — it is not a financial reward.</li><li><strong>Why D is wrong:</strong> Wages are paid to employees — entrepreneurs do not earn wages from their own business; they earn profit.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-1-role-of-business-enterprise:exam:a8f13398', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'exam', 'mcq', 1, '{"num": "Q9", "question": "This is called:", "options": ["Delegation", "Enterprise", "Market research", "Productivity"], "caseStudy": "A wine enthusiast has spotted an opportunity to turn their interest into a business by becoming a blogger.", "hint": "What is it called when someone spots an opportunity and acts on it to create a business?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: B — Enterprise</strong></p><ul><li><strong>Why B is correct:</strong> Enterprise is spotting an opportunity to provide a product or service people are willing to pay for. The wine enthusiast has identified a way to turn a hobby into a business — a classic example of enterprise.</li><li><strong>Why A is wrong:</strong> Delegation is the process of passing tasks or authority to others within a business.</li><li><strong>Why C is wrong:</strong> Market research is collecting information about customers and the market — not the act of creating a business.</li><li><strong>Why D is wrong:</strong> Productivity is output per worker — it measures efficiency, not enterprise.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-1-role-of-business-enterprise:exam:76d709cf', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Which one of the following is NOT a risk of entrepreneurship?", "options": ["Failing health", "Loss of money", "Self-satisfaction", "Strained personal relationships"], "hint": "Three of these are risks. One of them is actually a REWARD. Which one?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: C — Self-satisfaction</strong></p><ul><li><strong>Why C is correct (NOT a risk):</strong> Self-satisfaction is a non-financial REWARD of entrepreneurship — the personal pride and fulfilment from making a business idea succeed. This is one of the most frequently confused points in this topic.</li><li><strong>Why A is a risk:</strong> Failing health — the stress of running a business can cause serious mental and physical illness.</li><li><strong>Why B is a risk:</strong> Loss of money — personal savings invested in a failing business can be lost entirely.</li><li><strong>Why D is a risk:</strong> Strained personal relationships — long working hours and financial pressure put enormous strain on family and personal relationships.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-1-role-of-business-enterprise:exam:88ea4383', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'exam', 'mcq', 1, '{"num": "Q12", "question": "This is an example of:", "options": ["Discrimination", "Enterprise", "Flexible working", "Productivity"], "caseStudy": "Raj has developed an idea for a new business.", "hint": "Developing an idea for a new business is one of the three purposes of what concept?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Answer: B — Enterprise</strong></p><ul><li><strong>Why B is correct:</strong> Developing an idea for a new business is one of the three core purposes of enterprise (alongside spotting an opportunity and satisfying customer needs).</li><li><strong>Why A is wrong:</strong> Discrimination means treating someone unfairly based on protected characteristics such as race, gender, or age.</li><li><strong>Why C is wrong:</strong> Flexible working refers to arrangements where employees can vary their hours or place of work.</li><li><strong>Why D is wrong:</strong> Productivity measures output per worker — it is about efficiency in production, not starting a business.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-1-role-of-business-enterprise:exam:5948dcb2', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'exam', 'mcq', 1, '{"num": "Q14", "question": "Which one of the following is UNLIKELY to be a characteristic of a successful entrepreneur?", "options": ["Being able to create opportunities", "Being confident in new situations", "Being determined to work through problems", "Being uncomfortable with taking risks"], "hint": "All successful entrepreneurs share certain traits. One of these options is the OPPOSITE of what an entrepreneur should be.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Answer: D — Being uncomfortable with taking risks</strong></p><ul><li><strong>Why D is correct (UNLIKELY):</strong> A successful entrepreneur must be willing and comfortable with taking risks — it is a core characteristic. Being uncomfortable with risk would prevent someone from ever starting a business.</li><li><strong>Why A is wrong (it IS a characteristic):</strong> Creating opportunities is central to enterprise — spotting and acting on gaps in the market.</li><li><strong>Why B is wrong (it IS a characteristic):</strong> Confidence in new situations is one of the four official entrepreneurial characteristics.</li><li><strong>Why C is wrong (it IS a characteristic):</strong> Determination to work through problems is one of the four official entrepreneurial characteristics.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:2155846c', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "Which of the following is the correct definition of enterprise?", "options": ["The process of producing goods in a factory", "Spotting an opportunity to provide a product or service people are willing to buy", "Researching what customers want before opening a business", "The act of employing workers to grow a business"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Enterprise is defined as spotting an opportunity to provide a product or service that customers are willing to buy. It is about identifying a gap in the market and acting on it."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:01efe784', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "Two brothers are currently unemployed. They decide to set up their own window cleaning business. What is an entrepreneurial risk for the brothers?", "options": ["Cold weather", "Paying taxes", "Poor health", "Slippery ladders"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Poor health. Entrepreneurial risks are personal consequences of running a business, such as stress leading to illness. Cold weather and slippery ladders are working hazards. Paying taxes is a legal cost, not an entrepreneurial risk."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:e67dce30', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "Finley and Umi create personalised pictures using shells and pebbles. What would NOT be an appropriate reason for them to have started this business?", "options": ["They developed an idea for a business by making pictures that are unique", "They satisfied the needs of customers looking for sustainable gifts", "They spotted an opportunity to earn money from a leisure activity they loved", "They wanted to test their physical and mental health by working long hours"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Working long hours to test physical and mental health is a drawback of entrepreneurship — not a reason to start a business. Options A, B, and C are all valid entrepreneurial motivations: developing an idea, satisfying customer needs, and spotting an opportunity."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:9f6aac39', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "A plumbing firm is struggling to keep up with customer demand. What would help the business to succeed?", "options": ["Asking regular customers with blocked toilets to ring back another day", "Giving customers unrealistic appointment times", "Ignoring customer complaints about delays in fixing water leaks", "Planning all business activity and work schedules carefully"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Planning business activity carefully allows the firm to manage increased demand effectively. Options A, B, and C all involve poor customer service that would drive customers to competitors and damage the business''s reputation."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:0ade1566', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "Satisfying the needs of customers is:", "options": ["A legal requirement", "A market research task", "A purpose of business activity", "The role of the human resources function"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Satisfying the needs of customers is the core purpose of business activity. Businesses produce goods and services to meet customer needs and earn profit in return. It is not a legal requirement (A), not just a research task (B), and not limited to HR (D)."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:c688fd4d', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "Which of the following is a financial reward for enterprise?", "options": ["Authority", "Profit", "Success", "Wages"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Profit. Profit is the key financial reward of enterprise — the money remaining after all costs have been paid. Authority (A) is non-financial. Success (C) is too vague. Wages (D) are paid to employees, not earned by entrepreneurs as a reward for enterprise."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:8db6d04c', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "A wine enthusiast has spotted an opportunity to turn their interest into a business by becoming a blogger. This is called:", "options": ["Delegation", "Enterprise", "Market research", "Productivity"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Enterprise. Spotting an opportunity and acting on it to create a business is the definition of enterprise. Delegation (A) is passing tasks to others. Market research (C) is gathering information. Productivity (D) measures output per worker."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:76d709cf', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "Which one of the following is NOT a risk of entrepreneurship?", "options": ["Failing health", "Loss of money", "Self-satisfaction", "Strained personal relationships"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Self-satisfaction. Self-satisfaction is a non-financial REWARD of entrepreneurship — the personal pride felt when an idea succeeds. Failing health (A), loss of money (B), and strained relationships (D) are all genuine risks."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:13d14142', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "Raj has developed an idea for a new business. This is an example of:", "options": ["Discrimination", "Enterprise", "Flexible working", "Productivity"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Enterprise. Developing an idea for a new business is one of the three core purposes of enterprise. Discrimination (A) means treating people unfairly. Flexible working (C) relates to employment arrangements. Productivity (D) is output per unit of input."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:5948dcb2', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "Which one of the following is UNLIKELY to be a characteristic of a successful entrepreneur?", "options": ["Being able to create opportunities", "Being confident in new situations", "Being determined to work through problems", "Being uncomfortable with taking risks"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. A successful entrepreneur must be comfortable with taking risks — it is a core characteristic. Being uncomfortable with risk would prevent someone from starting a business. Options A, B, and C are all genuine entrepreneurial characteristics."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:4f89a737', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "An entrepreneur needs which of the following characteristics?", "options": ["Very well dressed at all times", "Know a person in business", "Very good at accounts", "Confident"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Confident. Confidence is one of the four core entrepreneurial characteristics alongside creativity, determination, and risk-taking. Being well dressed (A), knowing people (B), or being good at accounts (C) are not required characteristics."}'::jsonb),
('business:1-1-role-of-business-enterprise:mcq:e14b38ba', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a reward for risk taking when starting a business?", "options": ["Being able to invest money", "Being able to make profits for yourself", "Being independent", "Being able to see your own ideas work"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Investing money is something you DO when starting a business — it is an action taken (and a financial risk), not a reward received. Making profit (B), independence (C), and seeing your ideas succeed (D) are all genuine rewards of entrepreneurship."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:10f7588d', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "Businesses exist primarily to satisfy the needs of customers."}'::jsonb, '{"answer": true, "explain": "TRUE. The primary purpose of business activity is to satisfy the needs of customers by providing goods and services at a price people are willing to pay. Profit is the reward for doing this successfully."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:75f0b972', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "The four core characteristics of an entrepreneur include: creativity, determination, confidence, and hardworking."}'::jsonb, '{"answer": false, "explain": "FALSE. The four core characteristics are creativity, determination, confidence, and risk-taking. ''Hardworking'' is NOT accepted by the OCR mark scheme — writing it in an exam will score zero marks."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:0d2aa573', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "The financial risk of entrepreneurship includes the possibility of losing personal savings invested in the business."}'::jsonb, '{"answer": true, "explain": "TRUE. One of the main financial risks is that money invested — including personal savings — could be lost entirely if the business fails. This is the primary reason many people choose not to start businesses."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:d8a61170', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "Self-satisfaction is a risk of entrepreneurship."}'::jsonb, '{"answer": false, "explain": "FALSE. Self-satisfaction is a non-financial REWARD of entrepreneurship — the personal pride felt when an idea becomes a successful business. The risks include financial loss, failing health, and strained relationships."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:03ddd130', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "James Dyson demonstrated determination by trying thousands of different designs before succeeding with his bagless vacuum cleaner."}'::jsonb, '{"answer": true, "explain": "TRUE. Dyson tried over 5,000 designs over several years — the classic exam example of the entrepreneurial characteristic of determination (or perseverance)."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:f87c405c', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "Profit is a non-financial reward of enterprise."}'::jsonb, '{"answer": false, "explain": "FALSE. Profit is a FINANCIAL reward of enterprise — it is money. Non-financial rewards include independence, self-satisfaction, and changing customer attitudes."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:ef4733c8', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "An entrepreneur who starts a business to be their own boss is primarily motivated by the reward of independence."}'::jsonb, '{"answer": true, "explain": "TRUE. Independence — being your own boss and making your own decisions — is a key non-financial reward. Many entrepreneurs prioritise this over financial gain."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:ac32bf4c', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "Poor health is a financial risk of being an entrepreneur."}'::jsonb, '{"answer": false, "explain": "FALSE. Poor health is a NON-FINANCIAL risk. It refers to the mental and physical strain of running a business. The financial risk is the possible loss of money invested in the business."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:bb069620', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "Enterprise only applies to starting a completely new business — improving an existing product is not enterprise."}'::jsonb, '{"answer": false, "explain": "FALSE. Enterprise includes improving existing products or services, or providing them more cheaply. Apple did not invent the mobile phone but spotted how to improve it — that is enterprise. Spotting any opportunity counts."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:eb93efc1', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "The greater the risk taken by an entrepreneur, the greater the potential reward."}'::jsonb, '{"answer": true, "explain": "TRUE. This is a fundamental principle of entrepreneurship — higher risk is associated with the potential for higher rewards. This is why some entrepreneurs take large financial risks in pursuit of large profits."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:f0326266', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "''Motivated'' and ''well-organised'' are accepted characteristics of an entrepreneur in the OCR GCSE Business mark scheme."}'::jsonb, '{"answer": false, "explain": "FALSE. The OCR mark scheme specifically states that traits like ''motivated'', ''well-organised'', ''resilient'', ''teamwork'', and ''hardworking'' are NOT accepted. Always use the four official characteristics: creativity, risk-taking, determination, and confidence."}'::jsonb),
('business:1-1-role-of-business-enterprise:tf:e1a9e058', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tf', 'tf', 1, '{"question": "Strained personal relationships are a potential non-financial risk of running a business."}'::jsonb, '{"answer": true, "explain": "TRUE. Starting and running a business is extremely time-consuming. This can mean sacrificing holidays, missing family time, and placing enormous pressure on personal relationships — all non-financial costs of entrepreneurship."}'::jsonb),
('business:1-1-role-of-business-enterprise:learn:d9b2931e', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you must know and be able to use accurately in the exam.</p>\n<ul>\n  <li><strong>Entrepreneur:</strong> An individual who takes the risk of setting up and running a business enterprise.</li>\n  <li><strong>Enterprise:</strong> Seeing an opportunity to provide a product or service that people are willing to buy — often described as ''spotting an opportunity''.</li>\n  <li><strong>Opportunity:</strong> Taking advantage of a gap in the market or a possibility to provide something customers need that is not currently being met.</li>\n  <li><strong>Characteristics (of an entrepreneur):</strong> The personal features and qualities that make someone likely to succeed — the four accepted ones are: risk-taking, determination, confidence, and creativity.</li>\n  <li><strong>Risk:</strong> The possibility of a negative outcome when starting or running a business, such as financial loss, poor health, or strained relationships.</li>\n  <li><strong>Reward:</strong> The benefit gained from taking a risk — financial (profit) or non-financial (independence, self-satisfaction).</li>\n  <li><strong>Business activity:</strong> The process by which a business produces goods or provides services to satisfy the needs of customers.</li>\n</ul>", "question": "Which of these correctly distinguishes an ''entrepreneur'' from ''enterprise''?", "options": ["An entrepreneur is the risk-taker; enterprise is spotting an opportunity", "An entrepreneur is a synonym for a manager, while enterprise means a company''s turnover", "An entrepreneur is only someone who owns a large company; enterprise is a legal structure", "An entrepreneur and enterprise mean exactly the same thing and are interchangeable"]}'::jsonb, '{"answer": 0, "explain": "An entrepreneur is the individual who takes the risk of setting up and running a business, while enterprise is the concept of spotting an opportunity and acting on it."}'::jsonb),
('business:1-1-role-of-business-enterprise:learn:f355d127', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'learn', 'mcq', 1, '{"readingTitle": "What is Business Activity & Enterprise?", "reading": "<p>Businesses exist to <strong>satisfy the needs and wants of customers</strong>. They provide goods and services at a price people are willing to pay — and in return, the business earns profit.</p>\n<p>There are three main purposes of business enterprise and entrepreneurship:</p>\n<ul>\n  <li><strong>Spotting an opportunity:</strong> Identifying a gap in the market, improving an existing product or service, or producing something more cheaply than competitors.</li>\n  <li><strong>Developing an idea:</strong> Designing the product or service and planning how to produce it.</li>\n  <li><strong>Satisfying customer needs:</strong> Producing the product, providing the service, and marketing it to the right customers.</li>\n</ul>\n<p><strong>Enterprise</strong> is nothing new — for as long as trade has existed, people have spotted opportunities and acted on them. For example, street sellers appear with umbrellas the moment it rains: they identified a customer need and acted fast.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Google — Spotting an Opportunity</h4>\n  <p>Larry Page and Sergey Brin started Google by meeting in a garage. They spotted the need for a reliable search engine in the fast-growing computer market. That small idea grew into one of the world''s most valuable companies. Google is now developing drone technology to speed up deliveries — showing that enterprise means continuously spotting new opportunities.</p>\n  <p><strong>Takeaway:</strong> Enterprise is about constantly looking for unmet needs. Entrepreneurs don''t just wait — they act.</p>\n</div>", "question": "Which of the following is NOT one of the three core purposes of business enterprise?", "options": ["Maximising short-term share price", "Spotting an opportunity to sell", "Developing an idea for a product", "Satisfying customer needs directly"]}'::jsonb, '{"answer": 0, "explain": "The three core purposes are spotting an opportunity, developing an idea, and satisfying customer needs — maximising share price is not one of them."}'::jsonb),
('business:1-1-role-of-business-enterprise:learn:1be099ed', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'learn', 'mcq', 1, '{"readingTitle": "Characteristics of an Entrepreneur", "reading": "<p>Successful entrepreneurs share a set of key characteristics. You must be able to <strong>identify, explain, and apply</strong> these in the exam — especially for 6-mark questions that ask you to link them to a specific business.</p>\n<ul>\n  <li><strong>Creativity / Innovative:</strong> The ability to think up new ideas, design new products, or solve problems in original ways. James Dyson invented the bagless vacuum cleaner — something that had never existed before.</li>\n  <li><strong>Risk-taking:</strong> Being prepared to put personal money, time, or reputation at risk in the hope of a reward. Dyson gave up his paid job and invested his own savings to fund his venture — with no guarantee of success.</li>\n  <li><strong>Determination / Perseverance:</strong> Not giving up when things get difficult. Dyson tried over 5,000 designs before finding one that worked. This is the most commonly tested characteristic in context questions.</li>\n  <li><strong>Confidence / Self-belief:</strong> Believing that their idea will succeed and being able to inspire others to believe it too. An confident entrepreneur doesn''t say ''I can''t'' — they say ''I will''.</li>\n</ul>\n<p>⚠️ <strong>Examiner Warning:</strong> Do NOT write traits like <strong>''hardworking'', ''motivated'', ''well-organised'', ''resilient'', or ''teamwork''</strong>. The mark scheme explicitly states these will NOT be awarded marks. Stick to the four official characteristics above.</p>", "question": "Which of the four officially accepted entrepreneurial characteristics describes not giving up when problems arise?", "options": ["Determination", "Confidence", "Creativity", "Risk-taking"]}'::jsonb, '{"answer": 0, "explain": "Determination (or perseverance) is the characteristic of continuing to work through difficulties without giving up."}'::jsonb),
('business:1-1-role-of-business-enterprise:learn:b240cec5', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'learn', 'mcq', 1, '{"readingTitle": "Rewards vs Drawbacks of Risk Taking", "reading": "<p>When an entrepreneur takes a risk, they hope the <strong>rewards</strong> will outweigh the <strong>drawbacks</strong>. There are both financial and non-financial versions of each.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Rewards</div>\n    <div class=\"pro-item\"><strong>Financial (Profit):</strong> The greater the risk, the greater the potential reward. Entrepreneurs like Sir Richard Branson and Lord Sugar built personal fortunes by taking calculated risks.</div>\n    <div class=\"pro-item\"><strong>Independence:</strong> Being your own boss — making all your own decisions without answering to anyone else. The feeling of freedom can be a more powerful motivator than money for many entrepreneurs.</div>\n    <div class=\"pro-item\"><strong>Self-satisfaction:</strong> The personal pride of watching your own idea come to life and succeed. A business born from a hobby can bring deep fulfilment even when profit is modest.</div>\n    <div class=\"pro-item\"><strong>Changing customer habits:</strong> Anita Roddick founded The Body Shop on the principle that cosmetics should not be tested on animals — and changed the entire industry in doing so.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Drawbacks (Risks)</div>\n    <div class=\"con-item\"><strong>Financial loss:</strong> Life savings invested in a failing business may be lost entirely. This is the number one reason why many people never become entrepreneurs.</div>\n    <div class=\"con-item\"><strong>Failing health:</strong> The stress of running a business — whether it is struggling or booming — can cause serious mental and physical illness.</div>\n    <div class=\"con-item\"><strong>Strained relationships:</strong> Starting a business demands enormous time. Holidays are sacrificed, family time is lost, and personal relationships suffer as the business takes priority.</div>\n  </div>\n</div>", "question": "Which of the following is a NON-FINANCIAL reward of entrepreneurship?", "options": ["Independence", "Profit", "Turnover", "Wages"]}'::jsonb, '{"answer": 0, "explain": "Independence — being your own boss — is a non-financial reward. Profit is the financial reward, while turnover and wages are not entrepreneurial rewards."}'::jsonb),
('business:1-1-role-of-business-enterprise:learn:b644b36c', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'learn', 'mcq', 1, '{"readingTitle": "Real-World Case Studies", "reading": "<div class=\"case-study-box\">\n  <h4>Case Study: James Dyson — Determination, Creativity & Risk-Taking</h4>\n  <p>Frustrated with the poor performance of his vacuum cleaner, James Dyson decided to design a better one. He gave up his paid job, used his personal savings, and spent years in his garage creating over 5,000 different prototypes before producing the world''s first bagless vacuum cleaner.</p>\n  <p>When his first partnership (with Amway) failed, he didn''t stop — he formed his own company in 1991. Dyson Ltd now employs over 12,000 people worldwide and continues to innovate with vacuum cleaners, hand dryers, hair dryers, and air purifiers.</p>\n  <p><strong>Takeaway:</strong> Dyson demonstrates all four characteristics — determination (5,000+ designs), creativity (brand new product), confidence (believed in his idea despite early failure), and risk-taking (quit his job, used his personal savings).</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Zuber & Mohsin Issa — Spotting Opportunities</h4>\n  <p>The Issa brothers started with a single petrol station in Manchester in 2001. By continuously spotting new opportunities — adding supermarkets, coffee shops, and fast-food outlets to their petrol stations — they grew to over 5,000 outlets across Europe and the USA. In October 2020, they purchased a controlling stake in Asda from Walmart for £6.8 billion.</p>\n  <p><strong>Takeaway:</strong> Enterprise is not a one-time event. The Issa brothers show that successful entrepreneurship means spotting new opportunities at every stage of growth.</p>\n</div>", "question": "When using case study evidence to explain an entrepreneur''s characteristic, what must you always do to earn the application mark?", "options": ["Link the characteristic to specific evidence about the person", "Give a dictionary definition of the characteristic itself", "List as many different characteristics as you possibly can", "Compare the entrepreneur to a completely different case study"]}'::jsonb, '{"answer": 0, "explain": "Application marks require linking the characteristic to specific evidence from the case study, not just defining the term."}'::jsonb),
('business:1-1-role-of-business-enterprise:learn:e9fb805f', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'learn', 'mcq', 1, '{"readingTitle": "Evaluating Risk & Reward", "reading": "<p>When evaluating whether it is worth taking the risk of starting a business, you must <strong>weigh up both sides</strong> using the information provided. Evaluation questions rarely have a single correct answer — it depends on context.</p>\n<p>Key points to consider when writing an evaluation:</p>\n<ul>\n  <li>Does the entrepreneur have the right <strong>characteristics</strong> to succeed?</li>\n  <li>Is there genuine <strong>customer demand</strong> for the product or service?</li>\n  <li>How significant is the <strong>competition</strong>? Are there already established businesses in the market?</li>\n  <li>What is the entrepreneur''s <strong>financial position</strong> — can they afford to lose the money invested?</li>\n  <li>What are the <strong>non-financial costs</strong> (health, time, relationships) and how might these affect the entrepreneur''s ability to run the business long-term?</li>\n</ul>\n<p><strong>Evaluation point:</strong> Just because an entrepreneur is confident, determined, and willing to take a risk does <em>not</em> guarantee success. You must use specific evidence from the case study to justify your judgement — a conclusion that just repeats earlier points scores no evaluation marks.</p>", "question": "When answering an evaluation question about whether an entrepreneur should take a risk, what should your final judgement be based on?", "options": ["Specific evidence from the case study, not repeated earlier points", "Your own personal opinion about business in general", "Whichever side of the argument has more bullet points listed", "The entrepreneur''s characteristics alone, ignoring other factors"]}'::jsonb, '{"answer": 0, "explain": "Evaluation marks require judgements to be justified using specific evidence from the case study — a conclusion that just repeats earlier points scores no evaluation marks."}'::jsonb),
('business:1-1-role-of-business-enterprise:misc:368cbeac', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write ''hardworking'', ''motivated'', ''resilient'', or ''well-organised'' as characteristics of an entrepreneur.</p><p><strong>✅ The correct idea:</strong> The OCR mark scheme only accepts four characteristics: creativity, risk-taking, determination, and confidence. Writing other traits — no matter how sensible they seem — scores zero marks. The examiner is very specific about this.</p>", "question": "Which of these is one of the four characteristics officially accepted by the OCR mark scheme?", "options": ["Risk-taking", "Hardworking", "Well-organised", "Resilient"]}'::jsonb, '{"answer": 0, "explain": "Only creativity, risk-taking, determination and confidence are accepted; traits like hardworking, well-organised and resilient score zero marks."}'::jsonb),
('business:1-1-role-of-business-enterprise:misc:f518a170', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think ''paying taxes'' or ''cold weather'' are entrepreneurial risks.</p><p><strong>✅ The correct idea:</strong> Entrepreneurial risks are personal consequences of running a business: financial loss, failing health, and strained relationships. Taxes are business costs; weather is a working hazard — neither is an entrepreneurial risk in the OCR context.</p>", "question": "Which of these counts as a genuine ''entrepreneurial risk'' rather than a working hazard or business cost?", "options": ["Failing health due to stress", "Paying the yearly business taxes", "Cold winter weather", "Slippery wet ladders"]}'::jsonb, '{"answer": 0, "explain": "Entrepreneurial risks are personal consequences to the entrepreneur, such as failing health, financial loss and strained relationships — not routine costs or physical hazards of the job."}'::jsonb),
('business:1-1-role-of-business-enterprise:misc:cc76130f', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse ''risk'' and ''reward'' — writing self-satisfaction as a risk, or financial loss as a reward.</p><p><strong>✅ The correct idea:</strong> Risks are negative outcomes (financial loss, poor health, damaged relationships). Rewards are positive outcomes (profit, independence, self-satisfaction). Self-satisfaction is always a REWARD, never a risk.</p>", "question": "Self-satisfaction should always be classified as which of the following?", "options": ["A non-financial reward", "A non-financial risk", "A financial reward", "A financial risk"]}'::jsonb, '{"answer": 0, "explain": "Self-satisfaction is a positive outcome — a non-financial reward — and should never be written as a risk."}'::jsonb),
('business:1-1-role-of-business-enterprise:misc:2cad166a', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students explain what a characteristic means instead of applying it to the business in the case study.</p><p><strong>✅ The correct idea:</strong> For application marks, you MUST link the characteristic to the specific business. E.g. ''James Dyson showed creativity by designing a bagless vacuum cleaner that had never existed before.'' Never just define the term — always say HOW the entrepreneur showed it.</p>", "question": "To earn an application mark when explaining a characteristic, what must a student do?", "options": ["State exactly how the entrepreneur showed the trait", "Define what the characteristic word actually means", "Name as many characteristics as you possibly can", "Repeat the same characteristic in different words"]}'::jsonb, '{"answer": 0, "explain": "Application marks require showing HOW the entrepreneur demonstrated the characteristic using case study evidence, not simply defining the term."}'::jsonb),
('business:1-1-role-of-business-enterprise:misc:0e96c200', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think that because an entrepreneur has all four characteristics, their business is guaranteed to succeed.</p><p><strong>✅ The correct idea:</strong> Having the right characteristics increases the chance of success but does not guarantee it. Market conditions, competition, economic factors, and access to finance all affect whether a business succeeds. The examiner expects you to consider multiple factors when evaluating.</p>", "question": "Does having all four entrepreneurial characteristics guarantee that a business will succeed?", "options": ["No — competition, market conditions and finance also matter", "Yes — the four characteristics alone guarantee full success", "No — only risk-taking ever has any effect on success", "Yes — but only if the entrepreneur also has experience"]}'::jsonb, '{"answer": 0, "explain": "Having the right characteristics increases the chance of success but doesn''t guarantee it; other factors such as competition and finance also matter."}'::jsonb),
('business:1-1-role-of-business-enterprise:misc:1d9d3819', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write that wages are a financial reward for enterprise.</p><p><strong>✅ The correct idea:</strong> Wages are paid to EMPLOYEES by the business. The financial reward for the entrepreneur is PROFIT — the money left after all costs have been paid. Entrepreneurs do not earn wages from their own business.</p>", "question": "What is the correct financial reward earned by an entrepreneur from their own business?", "options": ["Profit", "Wages", "Salary", "Turnover"]}'::jsonb, '{"answer": 0, "explain": "Entrepreneurs earn profit — the money left after costs have been paid — not wages, which are paid to employees."}'::jsonb),
('business:1-1-role-of-business-enterprise:misc:0e9e6258', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think enterprise only means starting a brand-new product that has never existed before.</p><p><strong>✅ The correct idea:</strong> Enterprise includes spotting opportunities to improve existing products, fill gaps in existing markets, or deliver an existing service more cheaply or in a better location. Improving something that already exists is still enterprise.</p>", "question": "Which of the following counts as ''enterprise'' according to the OCR definition?", "options": ["Improving an existing product or making it cheaper", "Only inventing a completely brand-new product", "Only opening a business in a brand-new location", "Only starting a business with no competitors at all"]}'::jsonb, '{"answer": 0, "explain": "Enterprise includes spotting opportunities to improve existing products or provide them more cheaply or in a better way — not just brand-new inventions."}'::jsonb),
('business:1-1-role-of-business-enterprise:tips:4e989cca', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''State'', ''Identify''</strong> or <strong>''Give''</strong> question needs exactly <strong>one correct point</strong>. No explanation. No examples. No paragraphs.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific accepted point = 1 mark ✅</li>\n        <li>A vague or generic point = 0 marks ❌</li>\n        <li>A trait not on the accepted list (e.g. ''hardworking'') = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/><em>\"He worked very hard and was motivated.\"</em><br/>These are not accepted characteristics on the mark scheme.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/><em>\"Determination\"</em> or <em>\"Risk-taking\"</em><br/>Specific, accepted — earns the mark with one word.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> The most common correct answer in exams is ''risk taker''. Many students waste time writing full sentences when a single word earns the mark. Do not over-write on 1-mark questions.</p>\n      <p><strong>🚫 Never write:</strong> ''motivated'', ''well-organised'', ''resilient'', ''teamwork'', or ''hardworking'' for a characteristics question — the examiner explicitly will not award marks for these.</p>\n    ", "question": "How should you answer a 1-mark ''State'' or ''Identify'' question?", "options": ["Give exactly one clear, specific accepted point, no explanation", "Write a full paragraph explaining the point in a lot of detail", "Give three different points to be extra safe", "Explain the point fully using a case study example"]}'::jsonb, '{"answer": 0, "explain": "A 1-mark identify/state question only needs one clear, specific, accepted point — no explanation or examples are required."}'::jsonb),
('business:1-1-role-of-business-enterprise:tips:0b770448', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Point + Apply: The 2-Mark Formula", "reading": "\n      <p>A 2-mark <strong>''Explain''</strong> question needs a characteristic (K) <strong>plus</strong> an application to the specific business in the case study (APP). You <em>cannot</em> score the application mark without first scoring the knowledge mark.</p>\n      <p><strong>The Formula: K (1 mark) + APP (1 mark)</strong></p>\n      <ul>\n        <li><strong>K:</strong> Name the entrepreneurial characteristic clearly.</li>\n        <li><strong>APP:</strong> Explain specifically how this characteristic applies to the business in the case study.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"Julie and Cathy are creative. Creativity means thinking of new ideas.\"</em><br/>This just defines the word — it doesn''t apply it to the hairdressing business. Only 1 mark.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/><em>\"Julie and Cathy must be creative (K) so that they can offer a wide range of different styles for their customers'' hair, keeping people coming back to Sophisticutz rather than going to a competitor (APP).\"</em></p>\n      <p><strong>Useful sentence starters:</strong></p>\n      <ul>\n        <li><em>\"[Characteristic] is important because in the case of [business]...\"</em></li>\n        <li><em>\"[Business] demonstrates [characteristic] by...\"</em></li>\n      </ul>\n    ", "question": "What two elements must a 2-mark ''Explain'' answer contain to score both marks?", "options": ["A named characteristic (K) plus an application to the business (APP)", "A definition of the term followed by a second, different definition", "Two different characteristics named but neither one explained", "An opinion about the business followed by a short conclusion"]}'::jsonb, '{"answer": 0, "explain": "A 2-mark explain question requires Knowledge (naming the characteristic) plus Application (linking it to the specific business) — you cannot score APP without first scoring K."}'::jsonb),
('business:1-1-role-of-business-enterprise:tips:9206f5f4', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark <strong>''Analyse''</strong> question requires three steps in a chain of reasoning. You <em>cannot</em> score application or analysis marks without scoring understanding first.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the risk or characteristic and briefly explain what it means.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it directly to the specific business using evidence from the case study. Use phrases like <em>\"in the case of...\"</em> or <em>\"the text states that...\"</em></li>\n        <li><strong>Step 3 — Analysis (AN):</strong> Explain the <em>impact</em> on the business — think: money, customers, survival, reputation.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"A risk of starting a hairdressing business is financial loss. This means you could lose money.\"</em><br/>No application to Sophisticutz. No analysis of impact. Only scores 1 mark.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/><em>\"One risk of starting a hairdressing business in competition with Sophisticutz is financial loss (U). The text states there are already several established competitors occupying the best locations in town (APP). As a result, the new salon would struggle to attract customers in the early stages, meaning the entrepreneur could lose their personal savings before the business becomes profitable (AN).\"</em></p>\n      <p><strong>The ''So What?'' Rule:</strong><br/>Keep asking yourself ''So what?'' until you reach a bottom-line business impact (profit, costs, customers, survival).</p>\n    ", "question": "In a 3-mark ''Analyse'' answer, what does the final step (AN) require you to do?", "options": ["Explain the impact on the business, e.g. profit, customers, survival", "Repeat the application point again but in slightly different words", "Define the key term used earlier in the first step", "State a second characteristic shown by the entrepreneur"]}'::jsonb, '{"answer": 0, "explain": "The Analysis step requires explaining the impact of the point on the business — for example on money, customers, reputation or survival."}'::jsonb),
('business:1-1-role-of-business-enterprise:tips:afe0c0fd', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'tips', 'mcq', 1, '{"readingTitle": "Explain Three Characteristics — 6 marks — Three Mini-Analyses: Apply to the Business Every Time", "reading": "\n      <p>A 6-mark question asking you to ''explain three entrepreneurial characteristics'' is simply <strong>three 2-mark explain answers</strong> written one after another. For each characteristic you score: K (1 mark) + APP (1 mark).</p>\n      <p><strong>The Structure — Repeat 3 Times:</strong></p>\n      <ul>\n        <li><strong>Point 1:</strong> Name the characteristic (K) → Apply to the business using evidence from the text (APP)</li>\n        <li><strong>Point 2:</strong> Name the characteristic (K) → Apply to the business using evidence from the text (APP)</li>\n        <li><strong>Point 3:</strong> Name the characteristic (K) → Apply to the business using evidence from the text (APP)</li>\n      </ul>\n      <p><strong>⚠️ The Most Common Mistake:</strong><br/>Students write: <em>\"Creativity means thinking of new ideas.\"</em><br/>This just defines the word. You will NOT earn the application mark for explaining what a word means. You must say HOW the entrepreneur in the case study showed this characteristic — with evidence.</p>\n      <p><strong>✅ Model structure (Dyson question):</strong></p>\n      <ul>\n        <li><em>\"James Dyson showed determination (K) — he tried thousands of designs over several years without giving up (APP).\"</em></li>\n        <li><em>\"He was also creative (K) — he invented a completely new type of vacuum cleaner, the bagless design, that nobody had made before (APP).\"</em></li>\n        <li><em>\"Dyson was a risk taker (K) — he gave up his paid job and used his own savings to fund his new product, with no guarantee of success (APP).\"</em></li>\n      </ul>\n      <p><strong>Use the text!</strong> The examiner provides information about the entrepreneur specifically so you can apply it. Every application mark requires evidence from the case study.</p>\n    ", "question": "A 6-mark question asking you to ''explain three entrepreneurial characteristics'' is best answered using which structure?", "options": ["Three separate K + APP mini-answers, one for each trait", "One long paragraph covering all characteristics at once", "Three definitions of characteristics with no application", "One single characteristic explained in great depth"]}'::jsonb, '{"answer": 0, "explain": "The 6-mark question is simply three 2-mark explain answers in a row — each needs a named characteristic (K) plus application to the business (APP)."}'::jsonb),
