('business:1-1-role-of-business-enterprise:match:ba63d59d', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Confidence”?", "options": ["Being prepared to put personal money, time, or reputation into a business venture that may fail.", "The profit earned by an entrepreneur as a result of taking a risk and running a successful business.", "Being your own boss and having the freedom to make all your own business decisions.", "Believing strongly in your own ability to succeed and inspiring that belief in others."]}'::jsonb, '{"answer": 3, "explain": "“Confidence” means: Believing strongly in your own ability to succeed and inspiring that belief in others."}'::jsonb),
('business:1-1-role-of-business-enterprise:match:12b066a2', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Risk-taking”?", "options": ["The profit earned by an entrepreneur as a result of taking a risk and running a successful business.", "Being prepared to put personal money, time, or reputation into a business venture that may fail.", "Being your own boss and having the freedom to make all your own business decisions.", "The personal pride and fulfilment an entrepreneur feels from making their own idea a success."]}'::jsonb, '{"answer": 1, "explain": "“Risk-taking” means: Being prepared to put personal money, time, or reputation into a business venture that may fail."}'::jsonb),
