('business:1-1-role-of-business-enterprise:match:14c7dbc5', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Independence”?", "options": ["The personal pride and fulfilment an entrepreneur feels from making their own idea a success.", "The possibility that money invested in a business could be lost if the venture fails.", "The process of producing goods or providing services to satisfy the needs of customers.", "Being your own boss and having the freedom to make all your own business decisions."]}'::jsonb, '{"answer": 3, "explain": "“Independence” means: Being your own boss and having the freedom to make all your own business decisions."}'::jsonb),
('business:1-1-role-of-business-enterprise:match:cc20806d', 'business', 'business:1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Self-satisfaction”?", "options": ["The personal pride and fulfilment an entrepreneur feels from making their own idea a success.", "The possibility that money invested in a business could be lost if the venture fails.", "The process of producing goods or providing services to satisfy the needs of customers.", "A non-financial risk where long working hours and business pressure damage personal relationships."]}'::jsonb, '{"answer": 0, "explain": "“Self-satisfaction” means: The personal pride and fulfilment an entrepreneur feels from making their own idea a success."}'::jsonb),
